[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:DataDownload ;
                    schema1:contentUrl "https://example.org/videos/plate-tectonics-explained.mp4" ;
                    schema1:description "Full HD video file" ;
                    schema1:encodingFormat "video/mp4" ;
                    schema1:name "Video MP4" ] ;
            sh:resultMessage "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ;
                    sh:severity sh:Info ] ] .

